'use strict';

function renderTable(rows, options = {}) {
  if (!rows || rows.length === 0) {
    return '';
  }

  const align = options.align || [];
  const hasHeader = options.header || false;

  // Calculate column widths
  const numCols = rows[0].length;
  const colWidths = Array(numCols).fill(0);

  for (const row of rows) {
    for (let i = 0; i < row.length; i++) {
      colWidths[i] = Math.max(colWidths[i], row[i].length);
    }
  }

  // Render rows
  const renderedRows = [];
  for (let rowIdx = 0; rowIdx < rows.length; rowIdx++) {
    const row = rows[rowIdx];
    const cells = [];

    for (let colIdx = 0; colIdx < row.length; colIdx++) {
      const cell = row[colIdx];
      const isLastColumn = colIdx === row.length - 1;
      const width = colWidths[colIdx];
      const alignDir = align[colIdx] || 'left';

      let paddedCell;
      if (isLastColumn && alignDir === 'left') {
        // Last column, left-aligned: no padding
        paddedCell = cell;
      } else if (alignDir === 'right') {
        // Right-aligned: pad left
        paddedCell = cell.padStart(width);
      } else {
        // Left-aligned (not last column): pad right
        paddedCell = cell.padEnd(width);
      }

      cells.push(paddedCell);
    }

    const line = cells.join(' ');
    renderedRows.push(line);
  }

  // Handle header
  if (hasHeader) {
    const headerLine = renderedRows[0];
    const bodyLines = renderedRows.slice(1);
    const separatorLength = headerLine.length;
    const separator = '-'.repeat(separatorLength);

    return [headerLine, separator, ...bodyLines].join('\n');
  } else {
    return renderedRows.join('\n');
  }
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = { renderTable, renderTableLegacy };

